import React, { useCallback, useMemo, useState } from 'react';
import { LinErpListFilterBar, Select, dispatchAppToast } from '@linm-soft-org/linm-web-common-components';
import { useAppDispatch } from '../../../store/hooks';
import { analyticsService } from '../../../services/analytics/analyticsService';
import { formatNumber, formatVnd } from '../../../utils/formatters';
import { monthStartEnd } from '../../../utils/exportExcel';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import reportStyles from '../../../styles/erpReportPage.module.css';
import type { FinancialOverview } from '../../../services/analytics/models';
import { AnalyticsReportShell } from '../../../components/report';
import FinancialOverviewChart, { type ChartKind } from './FinancialOverviewChart';

const TEST_ID = 'erp-tong-quan-tai-chinh';
const PAGE_ID = 'tong-quan-tai-chinh';

const GRANULARITY_OPTIONS = [
  { value: 'day', label: 'Ngày' },
  { value: 'month', label: 'Tháng' },
  { value: 'year', label: 'Năm' },
];

const CHART_TYPE_OPTIONS = [
  { value: 'bar', label: 'Cột' },
  { value: 'line', label: 'Đường' },
  { value: 'pie', label: 'Tròn' },
];

const REVENUE_SERIES = [
  { dataKey: 'grossRevenue', name: 'DT trước giảm giá', color: '#1677ff' },
  { dataKey: 'discount', name: 'Giảm giá', color: '#fa8c16' },
  { dataKey: 'grossProfit', name: 'LN gộp', color: '#52c41a' },
];

const CASH_SERIES = [
  { dataKey: 'receipts', name: 'Thu', color: '#1677ff' },
  { dataKey: 'payments', name: 'Chi', color: '#fa8c16' },
];

const DashboardPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const initial = monthStartEnd();
  const [fromDate, setFromDate] = useState(initial.fromDate);
  const [toDate, setToDate] = useState(initial.toDate);
  const [granularity, setGranularity] = useState('month');
  const [revenueChartKind, setRevenueChartKind] = useState<ChartKind>('bar');
  const [cashChartKind, setCashChartKind] = useState<ChartKind>('bar');
  const [data, setData] = useState<FinancialOverview | null>(null);
  const [loading, setLoading] = useState(false);

  const handleLoad = useCallback(() => {
    setLoading(true);
    analyticsService
      .getFinancialOverview({ fromDate, toDate, granularity })
      .then(setData)
      .catch(err =>
        dispatchAppToast(dispatch, {
          message: getApiErrorMessage(err, 'Lỗi tải tổng quan tài chính'),
          type: 'error',
        }),
      )
      .finally(() => setLoading(false));
  }, [fromDate, toDate, granularity, dispatch]);

  const hasData = !!data && (data.revenueSeries.length > 0 || data.cashSeries.length > 0);

  const revenueChartData = useMemo(
    () =>
      (data?.revenueSeries ?? []).map(r => ({
        name: r.periodLabel,
        grossRevenue: r.grossRevenue,
        discount: r.discount,
        grossProfit: r.grossProfit,
      })),
    [data],
  );

  const cashChartData = useMemo(
    () =>
      (data?.cashSeries ?? []).map(c => ({
        name: c.periodLabel,
        receipts: c.receipts,
        payments: c.payments,
      })),
    [data],
  );

  const revenuePieData = useMemo(() => {
    if (!data) return [];
    return [
      { name: 'DT trước giảm giá', value: data.totalGrossRevenue, color: '#1677ff' },
      { name: 'Giảm giá', value: data.totalDiscount, color: '#fa8c16' },
      { name: 'LN gộp', value: data.totalGrossProfit, color: '#52c41a' },
    ].filter(d => d.value > 0);
  }, [data]);

  const cashPieData = useMemo(() => {
    if (!data) return [];
    return [
      { name: 'Thu', value: data.totalReceipts, color: '#1677ff' },
      { name: 'Chi', value: data.totalPayments, color: '#fa8c16' },
    ].filter(d => d.value > 0);
  }, [data]);

  const listFilters = useMemo(
    () => (
      <LinErpListFilterBar
        testIdPrefix={TEST_ID}
        fromDate={fromDate}
        toDate={toDate}
        onDateChange={(from, to) => {
          setFromDate(from ?? '');
          setToDate(to ?? '');
        }}
        dateLabel="Thời gian"
        expandDateRangeAriaLabel="Thêm ngày kết thúc"
        onSearch={handleLoad}
        searchAriaLabel="Xem"
        loading={loading}
        leading={(
          <div data-testid={`${TEST_ID}-field-granularity`}>
            <Select
              label="Kỳ"
              value={granularity}
              onChange={e => setGranularity(e.target.value)}
              options={GRANULARITY_OPTIONS}
              size="small"
            />
          </div>
        )}
      />
    ),
    [fromDate, toDate, granularity, handleLoad, loading],
  );

  return (
    <AnalyticsReportShell
      testId={TEST_ID}
      pageId={PAGE_ID}
      title="Tổng quan tài chính"
      titleIconClass="fas fa-tachometer-alt"
      listTitle="Tổng quan tài chính"
      loading={loading}
      hasData={hasData}
      filters={listFilters}
      onLoad={handleLoad}
      emptyMessage="Chọn kỳ và bấm Xem để tải số liệu từ sổ cái"
    >
      <p className={reportStyles.subtitle} style={{ margin: '0 0 12px' }}>
        Số liệu từ sổ cái — HĐ (doanh thu) · PT/PC (thu/chi)
      </p>

      <div className={reportStyles.kpiGrid}>
        <div className={reportStyles.kpiCard}>
          <div className={reportStyles.kpiLabel}>DT trước giảm giá</div>
          <div className={reportStyles.kpiValue}>{formatVnd(data?.totalGrossRevenue ?? 0)}</div>
        </div>
        <div className={reportStyles.kpiCard}>
          <div className={reportStyles.kpiLabel}>Giảm giá</div>
          <div className={reportStyles.kpiValue}>{formatVnd(data?.totalDiscount ?? 0)}</div>
        </div>
        <div className={reportStyles.kpiCard}>
          <div className={reportStyles.kpiLabel}>LN gộp</div>
          <div className={reportStyles.kpiValue}>{formatVnd(data?.totalGrossProfit ?? 0)}</div>
        </div>
        <div className={reportStyles.kpiCard}>
          <div className={reportStyles.kpiLabel}>Hóa đơn (HĐ)</div>
          <div className={reportStyles.kpiValue}>{formatNumber(data?.totalBillCount ?? 0)}</div>
        </div>
        <div className={reportStyles.kpiCard}>
          <div className={reportStyles.kpiLabel}>Thu (PT)</div>
          <div className={reportStyles.kpiValue}>{formatVnd(data?.totalReceipts ?? 0)}</div>
        </div>
        <div className={reportStyles.kpiCard}>
          <div className={reportStyles.kpiLabel}>Chi (PC)</div>
          <div className={reportStyles.kpiValue}>{formatVnd(data?.totalPayments ?? 0)}</div>
        </div>
      </div>

      <div className={reportStyles.chartSection}>
        <div className={reportStyles.chartSectionToolbar}>
          <div data-testid={`${TEST_ID}-revenue-chart-type`}>
            <Select
              label="Biểu đồ doanh thu"
              value={revenueChartKind}
              onChange={e => setRevenueChartKind(e.target.value as ChartKind)}
              options={CHART_TYPE_OPTIONS}
              size="small"
            />
          </div>
        </div>
        <FinancialOverviewChart
          testId={`${TEST_ID}-revenue-chart`}
          title="Doanh thu theo hóa đơn (HĐ)"
          chartKind={revenueChartKind}
          data={revenueChartData}
          series={REVENUE_SERIES}
          pieData={revenuePieData}
        />
      </div>

      <div className={reportStyles.chartSection}>
        <div className={reportStyles.chartSectionToolbar}>
          <div data-testid={`${TEST_ID}-cash-chart-type`}>
            <Select
              label="Biểu đồ thu/chi"
              value={cashChartKind}
              onChange={e => setCashChartKind(e.target.value as ChartKind)}
              options={CHART_TYPE_OPTIONS}
              size="small"
            />
          </div>
        </div>
        <FinancialOverviewChart
          testId={`${TEST_ID}-cash-chart`}
          title="Thu / chi theo phiếu thu · phiếu chi (PT/PC)"
          chartKind={cashChartKind}
          data={cashChartData}
          series={CASH_SERIES}
          pieData={cashPieData}
        />
      </div>
    </AnalyticsReportShell>
  );
};

export default DashboardPage;
